  1→package agent
  2→
  3→import "time"
  4→
  5→// AgentSession represents a coding session's data.
  6→// Each agent stores data in its native format (JSONL, SQLite, Markdown, etc.)
  7→// and only the originating agent can read/write it.
  8→//
  9→// Design: Sessions are NOT interoperable between agents. A session created by
 10→// Claude Code can only be read/written by Claude Code. This simplifies the
 11→// implementation as we don't need format conversion.
 12→//
 13→//nolint:revive // AgentSession is clearer than Session in context of the package
 14→type AgentSession struct {
 15→	SessionID  string
 16→	AgentName  AgentName
 17→	RepoPath   string
 18→	SessionRef string // Path/reference to session in agent's storage
 19→	StartTime  time.Time
 20→
 21→	// NativeData holds the session content in the agent's native format.
 22→	// Only the originating agent can interpret this data.
 23→	// Examples:
 24→	//   - Claude Code: raw JSONL bytes
 25→	//   - Cursor: serialized SQLite rows
 26→	//   - Aider: Markdown content
 27→	NativeData []byte
 28→
 29→	// Computed fields - populated by the agent when reading
 30→	ModifiedFiles []string
 31→	NewFiles      []string
 32→	DeletedFiles  []string
 33→
 34→	// Optional normalized entries - agents may populate this if needed
 35→	// for operations that benefit from structured access
 36→	Entries []SessionEntry
 37→}
 38→
 39→// SessionEntry represents a single entry in the session
 40→type SessionEntry struct {
 41→	UUID      string
 42→	Type      EntryType
 43→	Timestamp time.Time
 44→	Content   string
 45→
 46→	// Tool-specific fields
 47→	ToolName      string
 48→	ToolInput     interface{}
 49→	ToolOutput    interface{}
 50→	FilesAffected []string
 51→}
 52→
 53→// EntryType categorizes session entries
 54→type EntryType string
 55→
 56→const (
 57→	EntryUser      EntryType = "user"
 58→	EntryAssistant EntryType = "assistant"
 59→	EntryTool      EntryType = "tool"
 60→	EntrySystem    EntryType = "system"
 61→)
 62→
 63→// GetLastUserPrompt returns the last user message content
 64→func (s *AgentSession) GetLastUserPrompt() string {
 65→	for i := len(s.Entries) - 1; i >= 0; i-- {
 66→		if s.Entries[i].Type == EntryUser {
 67→			return s.Entries[i].Content
 68→		}
 69→	}
 70→	return ""
 71→}
 72→
 73→// GetLastAssistantResponse returns the last assistant message content
 74→func (s *AgentSession) GetLastAssistantResponse() string {
 75→	for i := len(s.Entries) - 1; i >= 0; i-- {
 76→		if s.Entries[i].Type == EntryAssistant {
 77→			return s.Entries[i].Content
 78→		}
 79→	}
 80→	return ""
 81→}
 82→
 83→// TruncateAtUUID returns a new session truncated at the given UUID (inclusive)
 84→func (s *AgentSession) TruncateAtUUID(uuid string) *AgentSession {
 85→	if uuid == "" {
 86→		return s
 87→	}
 88→
 89→	truncated := &AgentSession{
 90→		SessionID:  s.SessionID,
 91→		AgentName:  s.AgentName,
 92→		RepoPath:   s.RepoPath,
 93→		SessionRef: s.SessionRef,
 94→		StartTime:  s.StartTime,
 95→	}
 96→
 97→	for i, entry := range s.Entries {
 98→		truncated.Entries = append(truncated.Entries, entry)
 99→		if entry.UUID == uuid {
100→			truncated.Entries = s.Entries[:i+1]
101→			break
102→		}
103→	}
104→
105→	// Recompute file lists from truncated entries
106→	fileSet := make(map[string]bool)
107→	for _, entry := range truncated.Entries {
108→		for _, f := range entry.FilesAffected {
109→			if !fileSet[f] {
110→				fileSet[f] = true
111→				truncated.ModifiedFiles = append(truncated.ModifiedFiles, f)
112→			}
113→		}
114→	}
115→
116→	return truncated
117→}
118→
119→// FindToolResultUUID finds the UUID of the entry containing the tool result
120→// for the given tool use ID. Returns the UUID and true if found.
121→func (s *AgentSession) FindToolResultUUID(toolUseID string) (string, bool) {
122→	for _, entry := range s.Entries {
123→		if entry.Type == EntryTool && entry.UUID == toolUseID {
124→			return entry.UUID, true
125→		}
126→	}
127→	return "", false
128→}
