155→// FindCheckpointUUID finds the UUID of the message containing the tool_result
156→// for the given tool_use_id
157→func FindCheckpointUUID(lines []TranscriptLine, toolUseID string) (string, bool) {
158→	for _, line := range lines {
159→		if line.Type != "user" {
160→			continue
161→		}
162→
163→		var msg userMessageWithToolResults
164→		if err := json.Unmarshal(line.Message, &msg); err != nil {
165→			continue
166→		}
167→
168→		for _, block := range msg.Content {
169→			if block.Type == "tool_result" && block.ToolUseID == toolUseID {
170→				return line.UUID, true
171→			}
172→		}
173→	}
