177→// CalculateTokenUsage calculates token usage from a Claude Code transcript.
178→// This is specific to Claude/Anthropic's API format where each assistant message
179→// contains a usage object with input_tokens, output_tokens, and cache tokens.
180→//
181→// Due to streaming, multiple transcript rows may share the same message.id.
182→// We deduplicate by taking the row with the highest output_tokens for each message.id.
183→func CalculateTokenUsage(transcript []TranscriptLine) *agent.TokenUsage {
184→	// Map from message.id to the usage with highest output_tokens
185→	usageByMessageID := make(map[string]messageUsage)
186→
187→	for _, line := range transcript {
188→		if line.Type != "assistant" {
189→			continue
190→		}
191→
192→		var msg messageWithUsage
193→		if err := json.Unmarshal(line.Message, &msg); err != nil {
194→			continue
195→		}
196→
197→		if msg.ID == "" {
198→			continue
199→		}
200→
201→		// Keep the entry with highest output_tokens (final streaming state)
202→		existing, exists := usageByMessageID[msg.ID]
203→		if !exists || msg.Usage.OutputTokens > existing.OutputTokens {
204→			usageByMessageID[msg.ID] = msg.Usage
205→		}
206→	}
207→
208→	// Sum up all unique messages
209→	usage := &agent.TokenUsage{
210→		APICallCount: len(usageByMessageID),
211→	}
212→	for _, u := range usageByMessageID {
213→		usage.InputTokens += u.InputTokens
214→		usage.CacheCreationTokens += u.CacheCreationInputTokens
215→		usage.CacheReadTokens += u.CacheReadInputTokens
216→		usage.OutputTokens += u.OutputTokens
217→	}
218→
219→	return usage
220→}
221→
222→// CalculateTokenUsageFromFile calculates token usage from a Claude Code transcript file.
223→// If startLine > 0, only considers lines from startLine onwards.
224→func CalculateTokenUsageFromFile(path string, startLine int) (*agent.TokenUsage, error) {
225→	if path == "" {
226→		return &agent.TokenUsage{}, nil
227→	}
228→
229→	lines, _, err := transcript.ParseFromFileAtLine(path, startLine)
230→	if err != nil {
231→		return nil, err //nolint:wrapcheck // caller adds context
232→	}
233→
234→	return CalculateTokenUsage(lines), nil
235→}
