238→// --- Transcript flush sentinel ---
239→
240→// stopHookSentinel is the string that appears in Claude Code's hook_progress
241→// entry when the stop hook has been invoked, indicating the transcript is fully flushed.
242→const stopHookSentinel = "hooks claude-code stop"
243→
244→// waitForTranscriptFlush polls the transcript file for the stop hook sentinel.
245→// Falls back silently after a timeout.
246→func waitForTranscriptFlush(transcriptPath string, hookStartTime time.Time) {
247→	const (
248→		maxWait      = 3 * time.Second
249→		pollInterval = 50 * time.Millisecond
250→		tailBytes    = 4096
251→		maxSkew      = 2 * time.Second
252→	)
253→
254→	logCtx := logging.WithComponent(context.Background(), "agent.claudecode")
255→	deadline := time.Now().Add(maxWait)
256→	for time.Now().Before(deadline) {
257→		if checkStopSentinel(transcriptPath, tailBytes, hookStartTime, maxSkew) {
258→			logging.Debug(logCtx, "transcript flush sentinel found",
259→				slog.Duration("wait", time.Since(hookStartTime)),
260→			)
261→			return
262→		}
263→		time.Sleep(pollInterval)
264→	}
265→	logging.Warn(logCtx, "transcript flush sentinel not found within timeout, proceeding",
266→		slog.Duration("timeout", maxWait),
267→	)
268→}
269→
270→// checkStopSentinel reads the tail of the transcript file and looks for the sentinel.
271→func checkStopSentinel(path string, tailBytes int64, hookStartTime time.Time, maxSkew time.Duration) bool {
272→	f, err := os.Open(path) //nolint:gosec // path comes from agent hook input
273→	if err != nil {
274→		return false
275→	}
276→	defer f.Close()
277→
278→	info, err := f.Stat()
279→	if err != nil {
280→		return false
281→	}
282→	offset := info.Size() - tailBytes
283→	if offset < 0 {
284→		offset = 0
285→	}
286→	buf := make([]byte, info.Size()-offset)
287→	if _, err := f.ReadAt(buf, offset); err != nil {
288→		return false
289→	}
290→
291→	lines := strings.Split(string(buf), "\n")
292→	for _, line := range lines {
293→		line = strings.TrimSpace(line)
294→		if line == "" || !strings.Contains(line, stopHookSentinel) {
295→			continue
296→		}
297→
298→		var entry struct {
299→			Timestamp string `json:"timestamp"`
300→		}
301→		if json.Unmarshal([]byte(line), &entry) != nil || entry.Timestamp == "" {
302→			continue
303→		}
304→		ts, err := time.Parse(time.RFC3339Nano, entry.Timestamp)
305→		if err != nil {
306→			ts, err = time.Parse(time.RFC3339, entry.Timestamp)
307→			if err != nil {
308→				continue
309→			}
310→		}
311→		// Validate timestamp is within acceptable range:
312→		// - Not too far in the past (before hook started minus skew)
313→		// - Not too far in the future (after hook started plus skew)
314→		lowerBound := hookStartTime.Add(-maxSkew)
315→		upperBound := hookStartTime.Add(maxSkew)
316→		if ts.After(lowerBound) && ts.Before(upperBound) {
317→			return true
318→		}
319→	}
320→	return false
321→}
