378→// ChunkTranscript splits a Gemini JSON transcript by distributing messages across chunks.
379→// Gemini uses JSON format with a {"messages": [...]} structure, so chunking splits
380→// the messages array while preserving the JSON structure in each chunk.
381→func (g *GeminiCLIAgent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
382→	var transcript GeminiTranscript
383→	if err := json.Unmarshal(content, &transcript); err != nil {
384→		// Fall back to JSONL chunking if not valid Gemini JSON
385→		chunks, chunkErr := agent.ChunkJSONL(content, maxSize)
386→		if chunkErr != nil {
387→			return nil, fmt.Errorf("failed to chunk as JSONL: %w", chunkErr)
388→		}
389→		return chunks, nil
390→	}
391→
392→	if len(transcript.Messages) == 0 {
393→		return [][]byte{content}, nil
394→	}
395→
396→	var chunks [][]byte
397→	var currentMessages []GeminiMessage
398→	currentSize := len(`{"messages":[]}`) // Base JSON structure size
399→
400→	for i, msg := range transcript.Messages {
401→		// Marshal message to get its size
402→		msgBytes, err := json.Marshal(msg)
403→		if err != nil {
404→			logging.Warn(context.Background(), "failed to marshal Gemini message during chunking",
405→				slog.Int("message_index", i),
406→				slog.String("error", err.Error()),
407→			)
408→			continue
409→		}
410→		msgSize := len(msgBytes) + 1 // +1 for comma separator
411→
412→		if currentSize+msgSize > maxSize && len(currentMessages) > 0 {
413→			// Save current chunk
414→			chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
415→			if err != nil {
416→				return nil, fmt.Errorf("failed to marshal chunk: %w", err)
417→			}
418→			chunks = append(chunks, chunkData)
419→
420→			// Start new chunk
421→			currentMessages = nil
422→			currentSize = len(`{"messages":[]}`)
423→		}
424→
425→		currentMessages = append(currentMessages, msg)
426→		currentSize += msgSize
427→	}
428→
429→	// Add the last chunk
430→	if len(currentMessages) > 0 {
431→		chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
432→		if err != nil {
433→			return nil, fmt.Errorf("failed to marshal final chunk: %w", err)
434→		}
435→		chunks = append(chunks, chunkData)
436→	}
437→
438→	// Ensure we created at least one chunk (could be empty if all messages failed to marshal)
439→	if len(chunks) == 0 {
440→		return nil, errors.New("failed to create any chunks: all messages failed to marshal")
441→	}
442→
443→	return chunks, nil
444→}
445→
446→// ReassembleTranscript merges Gemini JSON chunks by combining their message arrays.
447→func (g *GeminiCLIAgent) ReassembleTranscript(chunks [][]byte) ([]byte, error) {
448→	var allMessages []GeminiMessage
449→
450→	for _, chunk := range chunks {
451→		var transcript GeminiTranscript
452→		if err := json.Unmarshal(chunk, &transcript); err != nil {
453→			return nil, fmt.Errorf("failed to unmarshal chunk: %w", err)
454→		}
455→		allMessages = append(allMessages, transcript.Messages...)
456→	}
457→
458→	result, err := json.Marshal(GeminiTranscript{Messages: allMessages})
459→	if err != nil {
460→		return nil, fmt.Errorf("failed to marshal reassembled transcript: %w", err)
461→	}
462→	return result, nil
463→}
