 12→// Transcript parsing types - Gemini CLI uses JSON format for session storage
 13→// Based on transcript_path format: ~/.gemini/tmp/<hash>/chats/session-<date>-<id>.json
 14→
 15→// Message type constants for Gemini transcripts
 16→const (
 17→	MessageTypeUser   = "user"
 18→	MessageTypeGemini = "gemini"
 19→)
 20→
 21→// GeminiTranscript represents the top-level structure of a Gemini session file
 22→type GeminiTranscript struct {
 23→	Messages []GeminiMessage `json:"messages"`
 24→}
 25→
 26→// GeminiMessage represents a single message in the transcript
 27→type GeminiMessage struct {
 28→	ID        string           `json:"id,omitempty"` // UUID for the message
 29→	Type      string           `json:"type"`         // MessageTypeUser or MessageTypeGemini
 30→	Content   string           `json:"content,omitempty"`
 31→	ToolCalls []GeminiToolCall `json:"toolCalls,omitempty"`
 32→}
 33→
 34→// UnmarshalJSON handles both string and array content formats in Gemini transcripts.
 35→// User messages use: "content": [{"text": "..."}] (array of objects)
 36→// Gemini messages use: "content": "response text" (string)
 37→func (m *GeminiMessage) UnmarshalJSON(data []byte) error {
 38→	// Use an alias to avoid infinite recursion
 39→	type Alias GeminiMessage
 40→	aux := &struct {
 41→		*Alias
 42→
 43→		Content json.RawMessage `json:"content,omitempty"`
 44→	}{
 45→		Alias: (*Alias)(m),
 46→	}
 47→
 48→	if err := json.Unmarshal(data, aux); err != nil {
 49→		return fmt.Errorf("failed to unmarshal message: %w", err)
 50→	}
 51→
 52→	if len(aux.Content) == 0 || string(aux.Content) == "null" {
 53→		m.Content = ""
 54→		return nil
 55→	}
 56→
 57→	// Try string first (most common for gemini messages)
 58→	var strContent string
 59→	if err := json.Unmarshal(aux.Content, &strContent); err == nil {
 60→		m.Content = strContent
 61→		return nil
 62→	}
 63→
 64→	// Try array of objects with "text" fields (user messages)
 65→	var parts []struct {
 66→		Text string `json:"text"`
 67→	}
 68→	if err := json.Unmarshal(aux.Content, &parts); err == nil {
 69→		var texts []string
 70→		for _, p := range parts {
 71→			if p.Text != "" {
 72→				texts = append(texts, p.Text)
 73→			}
 74→		}
 75→		m.Content = strings.Join(texts, "\n")
 76→		return nil
 77→	}
 78→
 79→	// Unknown format - leave content empty
 80→	return nil
 81→}
 82→
 83→// GeminiToolCall represents a tool call in a gemini message
 84→type GeminiToolCall struct {
 85→	ID     string                 `json:"id"`
 86→	Name   string                 `json:"name"`
 87→	Args   map[string]interface{} `json:"args"`
 88→	Status string                 `json:"status,omitempty"`
 89→}
 90→
 91→// ParseTranscript parses raw JSON content into a transcript structure
 92→func ParseTranscript(data []byte) (*GeminiTranscript, error) {
 93→	var transcript GeminiTranscript
 94→	if err := json.Unmarshal(data, &transcript); err != nil {
 95→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
 96→	}
 97→	return &transcript, nil
 98→}
 99→
100→// ExtractModifiedFiles extracts files modified by tool calls from transcript data
101→func ExtractModifiedFiles(data []byte) ([]string, error) {
102→	transcript, err := ParseTranscript(data)
103→	if err != nil {
104→		return nil, err
105→	}
106→
107→	return ExtractModifiedFilesFromTranscript(transcript), nil
108→}
109→
110→// ExtractModifiedFilesFromTranscript extracts files from a parsed transcript
111→func ExtractModifiedFilesFromTranscript(transcript *GeminiTranscript) []string {
112→	fileSet := make(map[string]bool)
113→	var files []string
114→
115→	for _, msg := range transcript.Messages {
116→		// Only process gemini messages (assistant messages)
117→		if msg.Type != MessageTypeGemini {
118→			continue
119→		}
120→
121→		// Process tool calls in this message
122→		for _, toolCall := range msg.ToolCalls {
123→			// Check if it's a file modification tool
124→			isModifyTool := false
125→			for _, name := range FileModificationTools {
126→				if toolCall.Name == name {
127→					isModifyTool = true
128→					break
129→				}
130→			}
131→
132→			if !isModifyTool {
133→				continue
134→			}
135→
136→			// Extract file path from args map
137→			var file string
138→			if fp, ok := toolCall.Args["file_path"].(string); ok && fp != "" {
139→				file = fp
140→			} else if p, ok := toolCall.Args["path"].(string); ok && p != "" {
141→				file = p
142→			} else if fn, ok := toolCall.Args["filename"].(string); ok && fn != "" {
143→				file = fn
144→			}
145→
146→			if file != "" && !fileSet[file] {
147→				fileSet[file] = true
148→				files = append(files, file)
149→			}
150→		}
151→	}
152→
153→	return files
154→}
155→
156→// ExtractLastUserPrompt extracts the last user message from transcript data
157→func ExtractLastUserPrompt(data []byte) (string, error) {
158→	transcript, err := ParseTranscript(data)
159→	if err != nil {
160→		return "", err
161→	}
162→
163→	return ExtractLastUserPromptFromTranscript(transcript), nil
164→}
165→
166→// ExtractLastUserPromptFromTranscript extracts the last user prompt from a parsed transcript
167→func ExtractLastUserPromptFromTranscript(transcript *GeminiTranscript) string {
168→	for i := len(transcript.Messages) - 1; i >= 0; i-- {
169→		msg := transcript.Messages[i]
170→		if msg.Type != MessageTypeUser {
171→			continue
172→		}
173→
174→		// Content is now a string field
175→		if msg.Content != "" {
176→			return msg.Content
177→		}
178→	}
179→	return ""
180→}
181→
182→// ExtractAllUserPrompts extracts all user messages from transcript data
183→func ExtractAllUserPrompts(data []byte) ([]string, error) {
184→	transcript, err := ParseTranscript(data)
185→	if err != nil {
186→		return nil, err
187→	}
188→
189→	return ExtractAllUserPromptsFromTranscript(transcript), nil
190→}
191→
192→// ExtractAllUserPromptsFromTranscript extracts all user prompts from a parsed transcript
193→func ExtractAllUserPromptsFromTranscript(transcript *GeminiTranscript) []string {
194→	var prompts []string
195→	for _, msg := range transcript.Messages {
196→		if msg.Type == MessageTypeUser && msg.Content != "" {
197→			prompts = append(prompts, msg.Content)
198→		}
199→	}
200→	return prompts
201→}
202→
203→// ExtractLastAssistantMessage extracts the last gemini response from transcript data
204→func ExtractLastAssistantMessage(data []byte) (string, error) {
205→	transcript, err := ParseTranscript(data)
206→	if err != nil {
207→		return "", err
208→	}
209→
210→	return ExtractLastAssistantMessageFromTranscript(transcript), nil
211→}
212→
213→// ExtractLastAssistantMessageFromTranscript extracts the last gemini response from a parsed transcript
214→func ExtractLastAssistantMessageFromTranscript(transcript *GeminiTranscript) string {
215→	for i := len(transcript.Messages) - 1; i >= 0; i-- {
216→		msg := transcript.Messages[i]
217→		if msg.Type == MessageTypeGemini && msg.Content != "" {
218→			return msg.Content
219→		}
220→	}
221→	return ""
222→}
223→
224→// GetLastMessageID returns the ID of the last message in the transcript.
225→// Returns empty string if the transcript is empty or the last message has no ID.
226→func GetLastMessageID(data []byte) (string, error) {
227→	transcript, err := ParseTranscript(data)
228→	if err != nil {
229→		return "", err
230→	}
231→	return GetLastMessageIDFromTranscript(transcript), nil
232→}
233→
234→// GetLastMessageIDFromTranscript returns the ID of the last message in a parsed transcript.
235→// Returns empty string if the transcript is empty or the last message has no ID.
236→func GetLastMessageIDFromTranscript(transcript *GeminiTranscript) string {
237→	if len(transcript.Messages) == 0 {
238→		return ""
239→	}
240→	return transcript.Messages[len(transcript.Messages)-1].ID
241→}
242→
243→// GetLastMessageIDFromFile reads a transcript file and returns the last message's ID.
244→// Returns empty string if the file doesn't exist, is empty, or has no messages with IDs.
245→func GetLastMessageIDFromFile(path string) (string, error) {
246→	if path == "" {
247→		return "", nil
248→	}
249→
250→	data, err := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
251→	if err != nil {
252→		if os.IsNotExist(err) {
253→			return "", nil
254→		}
255→		return "", fmt.Errorf("failed to read transcript: %w", err)
256→	}
257→
258→	if len(data) == 0 {
259→		return "", nil
260→	}
261→
262→	return GetLastMessageID(data)
263→}
264→
265→// SliceFromMessage returns a Gemini transcript scoped to messages starting from
266→// startMessageIndex. This is the Gemini equivalent of transcript.SliceFromLine —
267→// for Gemini's single JSON blob, scoping is done by message index rather than line offset.
268→// Returns the original data if startMessageIndex <= 0.
269→// Returns nil if startMessageIndex exceeds the number of messages.
270→func SliceFromMessage(data []byte, startMessageIndex int) []byte {
271→	if len(data) == 0 || startMessageIndex <= 0 {
272→		return data
273→	}
274→
275→	t, err := ParseTranscript(data)
276→	if err != nil {
277→		return nil
278→	}
279→
280→	if startMessageIndex >= len(t.Messages) {
281→		return nil
282→	}
283→
284→	scoped := &GeminiTranscript{
285→		Messages: t.Messages[startMessageIndex:],
286→	}
287→
288→	out, err := json.Marshal(scoped)
289→	if err != nil {
290→		return nil
291→	}
292→	return out
293→}
294→
295→// CalculateTokenUsage calculates token usage from a Gemini transcript.
296→// This is specific to Gemini's API format where each message may have a tokens object
297→// with input, output, cached, thoughts, tool, and total counts.
298→// Only processes messages from startMessageIndex onwards (0-indexed).
299→func CalculateTokenUsage(data []byte, startMessageIndex int) *agent.TokenUsage {
300→	var transcript struct {
301→		Messages []geminiMessageWithTokens `json:"messages"`
302→	}
303→
304→	if err := json.Unmarshal(data, &transcript); err != nil {
305→		return &agent.TokenUsage{}
306→	}
307→
308→	usage := &agent.TokenUsage{}
309→
310→	for i, msg := range transcript.Messages {
311→		// Skip messages before startMessageIndex
312→		if i < startMessageIndex {
313→			continue
314→		}
315→
316→		// Only count tokens from gemini (assistant) messages
317→		if msg.Type != MessageTypeGemini {
318→			continue
319→		}
320→
321→		if msg.Tokens == nil {
322→			continue
323→		}
324→
325→		usage.APICallCount++
326→		usage.InputTokens += msg.Tokens.Input
327→		usage.OutputTokens += msg.Tokens.Output
328→		usage.CacheReadTokens += msg.Tokens.Cached
329→	}
330→
331→	return usage
332→}
333→
334→// CalculateTokenUsageFromFile calculates token usage from a Gemini transcript file.
335→// If startMessageIndex > 0, only considers messages from that index onwards.
336→func CalculateTokenUsageFromFile(path string, startMessageIndex int) (*agent.TokenUsage, error) {
337→	if path == "" {
338→		return &agent.TokenUsage{}, nil
339→	}
340→
341→	data, err := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
342→	if err != nil {
343→		if os.IsNotExist(err) {
344→			return &agent.TokenUsage{}, nil
345→		}
346→		return nil, fmt.Errorf("failed to read transcript: %w", err)
347→	}
348→
349→	return CalculateTokenUsage(data, startMessageIndex), nil
350→}
