 20→// HookNames returns the hook verbs Gemini CLI supports.
 21→// Delegates to GetHookNames for backward compatibility.
 22→func (g *GeminiCLIAgent) HookNames() []string {
 23→	return g.GetHookNames()
 24→}
 25→
 26→// ParseHookEvent translates a Gemini CLI hook into a normalized lifecycle Event.
 27→// Returns nil if the hook has no lifecycle significance (e.g., pass-through hooks).
 28→func (g *GeminiCLIAgent) ParseHookEvent(hookName string, stdin io.Reader) (*agent.Event, error) {
 29→	switch hookName {
 30→	case HookNameSessionStart:
 31→		return g.parseSessionStart(stdin)
 32→	case HookNameBeforeAgent:
 33→		return g.parseTurnStart(stdin)
 34→	case HookNameAfterAgent:
 35→		return g.parseTurnEnd(stdin)
 36→	case HookNameSessionEnd:
 37→		return g.parseSessionEnd(stdin)
 38→	case HookNamePreCompress:
 39→		return g.parseCompaction(stdin)
 40→	case HookNameBeforeTool, HookNameAfterTool, HookNameBeforeModel,
 41→		HookNameAfterModel, HookNameBeforeToolSelection, HookNameNotification:
 42→		// Acknowledged hooks with no lifecycle action
 43→		return nil, nil //nolint:nilnil // nil event = no lifecycle action
 44→	default:
 45→		return nil, nil //nolint:nilnil // Unknown hooks have no lifecycle action
 46→	}
 47→}
