 49→// ReadTranscript reads the raw JSON transcript bytes for a session.
 50→func (g *GeminiCLIAgent) ReadTranscript(sessionRef string) ([]byte, error) {
 51→	data, err := os.ReadFile(sessionRef) //nolint:gosec // Path comes from agent hook input
 52→	if err != nil {
 53→		return nil, fmt.Errorf("failed to read transcript: %w", err)
 54→	}
 55→	return data, nil
 56→}
