 58→// ExtractPrompts extracts user prompts from the transcript starting at the given message offset.
 59→func (g *GeminiCLIAgent) ExtractPrompts(sessionRef string, fromOffset int) ([]string, error) {
 60→	data, err := os.ReadFile(sessionRef) //nolint:gosec // Path comes from agent hook input
 61→	if err != nil {
 62→		return nil, fmt.Errorf("failed to read transcript: %w", err)
 63→	}
 64→
 65→	t, parseErr := ParseTranscript(data)
 66→	if parseErr != nil {
 67→		return nil, fmt.Errorf("failed to parse transcript: %w", parseErr)
 68→	}
 69→
 70→	var prompts []string
 71→	for i := fromOffset; i < len(t.Messages); i++ {
 72→		msg := t.Messages[i]
 73→		if msg.Type == MessageTypeUser && msg.Content != "" {
 74→			prompts = append(prompts, msg.Content)
 75→		}
 76→	}
 77→	return prompts, nil
 78→}
