162→// readAndParse reads stdin and unmarshals JSON into the given type.
163→func readAndParse[T any](stdin io.Reader) (*T, error) {
164→	data, err := io.ReadAll(stdin)
165→	if err != nil {
166→		return nil, fmt.Errorf("failed to read hook input: %w", err)
167→	}
168→	if len(data) == 0 {
169→		return nil, errors.New("empty hook input")
170→	}
171→	var result T
172→	if err := json.Unmarshal(data, &result); err != nil {
173→		return nil, fmt.Errorf("failed to parse hook input: %w", err)
174→	}
175→	return &result, nil
176→}
