11→// ReadRawHooks reads the raw hooks map from a settings file.
12→// settingsDir is the directory name (e.g., ".claude" or ".gemini").
13→func ReadRawHooks(t *testing.T, tempDir, settingsDir string) map[string]json.RawMessage {
14→	t.Helper()
15→	settingsPath := filepath.Join(tempDir, settingsDir, "settings.json")
16→	data, err := os.ReadFile(settingsPath) //nolint:gosec // Test utility, path constructed from test tempDir
17→	if err != nil {
18→		t.Fatalf("failed to read settings.json: %v", err)
19→	}
20→
21→	var rawSettings map[string]json.RawMessage
22→	if err := json.Unmarshal(data, &rawSettings); err != nil {
23→		t.Fatalf("failed to parse settings.json: %v", err)
24→	}
25→
26→	var rawHooks map[string]json.RawMessage
27→	if hooksRaw, ok := rawSettings["hooks"]; ok {
28→		if err := json.Unmarshal(hooksRaw, &rawHooks); err != nil {
29→			t.Fatalf("failed to parse hooks: %v", err)
30→		}
31→	}
32→	return rawHooks
33→}
