110→// handleLifecycleTurnStart handles turn start: captures pre-prompt state,
111→// ensures strategy setup, initializes session.
112→func handleLifecycleTurnStart(ag agent.Agent, event *agent.Event) error {
113→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
114→	logging.Info(logCtx, "turn-start",
115→		slog.String("event", event.Type.String()),
116→		slog.String("session_id", event.SessionID),
117→		slog.String("session_ref", event.SessionRef),
118→	)
119→
120→	sessionID := event.SessionID
121→	if sessionID == "" {
122→		return fmt.Errorf("no session_id in %s event", event.Type)
123→	}
124→	if err := validation.ValidateSessionID(sessionID); err != nil {
125→		return fmt.Errorf("invalid %s event: %w", event.Type, err)
126→	}
127→
128→	// Capture pre-prompt state (including transcript position via TranscriptAnalyzer)
129→	if err := CapturePrePromptState(ag, sessionID, event.SessionRef); err != nil {
130→		return err
131→	}
132→
133→	// Ensure strategy setup and initialize session
134→	strat := GetStrategy()
135→
136→	if err := strat.EnsureSetup(); err != nil {
137→		fmt.Fprintf(os.Stderr, "Warning: failed to ensure strategy setup: %v\n", err)
138→	}
139→
140→	if initializer, ok := strat.(strategy.SessionInitializer); ok {
141→		agentType := ag.Type()
142→		if err := initializer.InitializeSession(sessionID, agentType, event.SessionRef, event.Prompt); err != nil {
143→			fmt.Fprintf(os.Stderr, "Warning: failed to initialize session state: %v\n", err)
144→		}
145→	}
146→
147→	return nil
148→}
149→
150→// handleLifecycleTurnEnd handles turn end: validates transcript, extracts metadata,
151→// detects file changes, saves step + checkpoint, transitions phase.
152→//
153→//nolint:maintidx // high complexity due to sequential orchestration of 8 steps (validation, extraction, file detection, filtering, token calc, step save, phase transition, cleanup) - splitting would obscure the flow
154→func handleLifecycleTurnEnd(ag agent.Agent, event *agent.Event) error {
155→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
156→	logging.Info(logCtx, "turn-end",
157→		slog.String("event", event.Type.String()),
158→		slog.String("session_id", event.SessionID),
159→		slog.String("session_ref", event.SessionRef),
160→	)
161→
162→	sessionID := event.SessionID
163→	if sessionID == "" {
164→		sessionID = unknownSessionID
165→	}
166→
167→	transcriptRef := event.SessionRef
168→	if transcriptRef == "" || !fileExists(transcriptRef) {
169→		return fmt.Errorf("transcript file not found: %s", transcriptRef)
170→	}
171→
172→	// Early check: bail out quickly if the repo has no commits yet.
173→	if repo, err := strategy.OpenRepository(); err == nil && strategy.IsEmptyRepository(repo) {
174→		fmt.Fprintln(os.Stderr, "Entire: skipping checkpoint. Will activate after first commit.")
175→		return NewSilentError(strategy.ErrEmptyRepository)
176→	}
177→
178→	// Create session metadata directory
179→	sessionDir := paths.SessionMetadataDirFromSessionID(sessionID)
180→	sessionDirAbs, err := paths.AbsPath(sessionDir)
181→	if err != nil {
182→		sessionDirAbs = sessionDir
183→	}
184→	if err := os.MkdirAll(sessionDirAbs, 0o750); err != nil {
185→		return fmt.Errorf("failed to create session directory: %w", err)
186→	}
187→
188→	// If agent implements TranscriptPreparer, wait for transcript to be ready
189→	if preparer, ok := ag.(agent.TranscriptPreparer); ok {
190→		if err := preparer.PrepareTranscript(transcriptRef); err != nil {
191→			fmt.Fprintf(os.Stderr, "Warning: failed to prepare transcript: %v\n", err)
192→		}
193→	}
194→
195→	// Copy transcript to session directory
196→	transcriptData, err := ag.ReadTranscript(transcriptRef)
197→	if err != nil {
198→		return fmt.Errorf("failed to read transcript: %w", err)
199→	}
200→	logFile := filepath.Join(sessionDirAbs, paths.TranscriptFileName)
201→	if err := os.WriteFile(logFile, transcriptData, 0o600); err != nil {
202→		return fmt.Errorf("failed to write transcript: %w", err)
203→	}
204→	fmt.Fprintf(os.Stderr, "Copied transcript to: %s\n", sessionDir+"/"+paths.TranscriptFileName)
205→
206→	// Load pre-prompt state (captured on TurnStart)
207→	preState, err := LoadPrePromptState(sessionID)
208→	if err != nil {
209→		fmt.Fprintf(os.Stderr, "Warning: failed to load pre-prompt state: %v\n", err)
210→	}
211→
212→	// Determine transcript offset
213→	transcriptOffset := resolveTranscriptOffset(preState, sessionID)
214→
215→	// Extract metadata via agent interface (prompts, summary, modified files)
216→	var allPrompts []string
217→	var summary string
218→	var modifiedFiles []string
219→	var newTranscriptPosition int
220→
221→	// Compute subagents directory for agents that support subagent extraction
222→	subagentsDir := filepath.Join(filepath.Dir(transcriptRef), "subagents")
223→
224→	if analyzer, ok := ag.(agent.TranscriptAnalyzer); ok {
225→		// Extract prompts
226→		if prompts, promptErr := analyzer.ExtractPrompts(transcriptRef, transcriptOffset); promptErr != nil {
227→			fmt.Fprintf(os.Stderr, "Warning: failed to extract prompts: %v\n", promptErr)
228→		} else {
229→			allPrompts = prompts
230→		}
231→
232→		// Extract summary
233→		if s, sumErr := analyzer.ExtractSummary(transcriptRef); sumErr != nil {
234→			fmt.Fprintf(os.Stderr, "Warning: failed to extract summary: %v\n", sumErr)
235→		} else {
236→			summary = s
237→		}
238→
239→		// Extract modified files - prefer SubagentAwareExtractor if available to include subagent files
240→		if subagentExtractor, subOk := ag.(agent.SubagentAwareExtractor); subOk {
241→			if files, fileErr := subagentExtractor.ExtractAllModifiedFiles(transcriptRef, transcriptOffset, subagentsDir); fileErr != nil {
242→				fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files (with subagents): %v\n", fileErr)
243→			} else {
244→				modifiedFiles = files
245→			}
246→			// Get position from basic analyzer
247→			if _, pos, posErr := analyzer.ExtractModifiedFilesFromOffset(transcriptRef, transcriptOffset); posErr == nil {
248→				newTranscriptPosition = pos
249→			}
250→		} else {
251→			// Fall back to basic extraction (main transcript only)
252→			if files, pos, fileErr := analyzer.ExtractModifiedFilesFromOffset(transcriptRef, transcriptOffset); fileErr != nil {
253→				fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files: %v\n", fileErr)
254→			} else {
255→				modifiedFiles = files
256→				newTranscriptPosition = pos
257→			}
258→		}
259→	}
260→
261→	// Write prompts file
262→	promptFile := filepath.Join(sessionDirAbs, paths.PromptFileName)
263→	promptContent := strings.Join(allPrompts, "\n\n---\n\n")
264→	if err := os.WriteFile(promptFile, []byte(promptContent), 0o600); err != nil {
265→		return fmt.Errorf("failed to write prompt file: %w", err)
266→	}
267→	fmt.Fprintf(os.Stderr, "Extracted %d prompt(s) to: %s\n", len(allPrompts), sessionDir+"/"+paths.PromptFileName)
268→
269→	// Write summary file
270→	summaryFile := filepath.Join(sessionDirAbs, paths.SummaryFileName)
271→	if err := os.WriteFile(summaryFile, []byte(summary), 0o600); err != nil {
272→		return fmt.Errorf("failed to write summary file: %w", err)
273→	}
274→	fmt.Fprintf(os.Stderr, "Extracted summary to: %s\n", sessionDir+"/"+paths.SummaryFileName)
275→
276→	// Generate commit message from last prompt
277→	lastPrompt := ""
278→	if len(allPrompts) > 0 {
279→		lastPrompt = allPrompts[len(allPrompts)-1]
280→	}
281→	commitMessage := generateCommitMessage(lastPrompt)
282→	fmt.Fprintf(os.Stderr, "Using commit message: %s\n", commitMessage)
283→
284→	// Get repo root for path normalization
285→	repoRoot, err := paths.RepoRoot()
286→	if err != nil {
287→		return fmt.Errorf("failed to get repo root: %w", err)
288→	}
289→
290→	var preUntrackedFiles []string
291→	if preState != nil {
292→		fmt.Fprintf(os.Stderr, "Pre-prompt state: %d pre-existing untracked files\n", len(preState.UntrackedFiles))
293→		preUntrackedFiles = preState.PreUntrackedFiles()
294→	}
295→
296→	// Detect file changes via git status
297→	changes, err := DetectFileChanges(preUntrackedFiles)
298→	if err != nil {
299→		fmt.Fprintf(os.Stderr, "Warning: failed to compute file changes: %v\n", err)
300→	}
301→
302→	// Filter and normalize all paths
303→	relModifiedFiles := FilterAndNormalizePaths(modifiedFiles, repoRoot)
304→	var relNewFiles, relDeletedFiles []string
305→	if changes != nil {
306→		relNewFiles = FilterAndNormalizePaths(changes.New, repoRoot)
307→		relDeletedFiles = FilterAndNormalizePaths(changes.Deleted, repoRoot)
308→	}
309→
310→	// Check if there are any changes
311→	totalChanges := len(relModifiedFiles) + len(relNewFiles) + len(relDeletedFiles)
312→	if totalChanges == 0 {
313→		fmt.Fprintf(os.Stderr, "No files were modified during this session\n")
314→		fmt.Fprintf(os.Stderr, "Skipping commit\n")
315→		transitionSessionTurnEnd(sessionID)
316→		if cleanupErr := CleanupPrePromptState(sessionID); cleanupErr != nil {
317→			fmt.Fprintf(os.Stderr, "Warning: failed to cleanup pre-prompt state: %v\n", cleanupErr)
318→		}
319→		return nil
320→	}
321→
322→	// Log file changes
323→	logFileChanges(relModifiedFiles, relNewFiles, relDeletedFiles)
324→
325→	// Create context file
326→	contextFile := filepath.Join(sessionDirAbs, paths.ContextFileName)
327→	if err := createContextFile(contextFile, commitMessage, sessionID, allPrompts, summary); err != nil {
328→		return fmt.Errorf("failed to create context file: %w", err)
329→	}
330→	fmt.Fprintf(os.Stderr, "Created context file: %s\n", sessionDir+"/"+paths.ContextFileName)
331→
332→	// Get git author
333→	author, err := GetGitAuthor()
334→	if err != nil {
335→		return fmt.Errorf("failed to get git author: %w", err)
336→	}
337→
338→	// Get strategy and agent type
339→	strat := GetStrategy()
340→	agentType := ag.Type()
341→
342→	// Get transcript position/identifier from pre-prompt state
343→	var transcriptIdentifierAtStart string
344→	var transcriptLinesAtStart int
345→	if preState != nil {
346→		transcriptIdentifierAtStart = preState.LastTranscriptIdentifier
347→		transcriptLinesAtStart = preState.TranscriptOffset
348→	}
349→
350→	// Calculate token usage - prefer SubagentAwareExtractor to include subagent tokens
351→	var tokenUsage *agent.TokenUsage
352→	if subagentExtractor, ok := ag.(agent.SubagentAwareExtractor); ok {
353→		usage, tokenErr := subagentExtractor.CalculateTotalTokenUsage(transcriptRef, transcriptLinesAtStart, subagentsDir)
354→		if tokenErr != nil {
355→			fmt.Fprintf(os.Stderr, "Warning: failed to calculate token usage (with subagents): %v\n", tokenErr)
356→		} else {
357→			tokenUsage = usage
358→		}
359→	} else if calculator, ok := ag.(agent.TokenCalculator); ok {
360→		// Fall back to basic token calculation (main transcript only)
361→		usage, tokenErr := calculator.CalculateTokenUsage(transcriptRef, transcriptLinesAtStart)
362→		if tokenErr != nil {
363→			fmt.Fprintf(os.Stderr, "Warning: failed to calculate token usage: %v\n", tokenErr)
364→		} else {
365→			tokenUsage = usage
366→		}
367→	}
368→
369→	// Build fully-populated step context and delegate to strategy
370→	ctx := strategy.StepContext{
371→		SessionID:                sessionID,
372→		ModifiedFiles:            relModifiedFiles,
373→		NewFiles:                 relNewFiles,
374→		DeletedFiles:             relDeletedFiles,
375→		MetadataDir:              sessionDir,
376→		MetadataDirAbs:           sessionDirAbs,
377→		CommitMessage:            commitMessage,
378→		TranscriptPath:           transcriptRef,
379→		AuthorName:               author.Name,
380→		AuthorEmail:              author.Email,
381→		AgentType:                agentType,
382→		StepTranscriptIdentifier: transcriptIdentifierAtStart,
383→		StepTranscriptStart:      transcriptLinesAtStart,
384→		TokenUsage:               tokenUsage,
385→	}
386→
387→	if err := strat.SaveStep(ctx); err != nil {
388→		return fmt.Errorf("failed to save step: %w", err)
389→	}
390→
391→	// Update session state transcript position for auto-commit strategy
392→	if strat.Name() == strategy.StrategyNameAutoCommit && newTranscriptPosition > 0 {
393→		updateAutoCommitTranscriptPosition(sessionID, newTranscriptPosition)
394→	}
395→
396→	// Transition session phase and cleanup
397→	transitionSessionTurnEnd(sessionID)
398→	if cleanupErr := CleanupPrePromptState(sessionID); cleanupErr != nil {
399→		fmt.Fprintf(os.Stderr, "Warning: failed to cleanup pre-prompt state: %v\n", cleanupErr)
400→	}
401→
402→	return nil
403→}
404→
405→// handleLifecycleCompaction handles context compaction: saves current progress
406→// but stays in ACTIVE phase (unlike TurnEnd which transitions to IDLE).
407→// Also resets the transcript offset since the transcript may be truncated.
408→func handleLifecycleCompaction(ag agent.Agent, event *agent.Event) error {
409→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
410→	logging.Info(logCtx, "compaction",
411→		slog.String("event", event.Type.String()),
412→		slog.String("session_id", event.SessionID),
413→	)
414→
415→	// Fire EventCompaction to trigger ActionCondenseIfFilesTouched (stays in ACTIVE)
416→	sessionID := event.SessionID
417→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
418→	if loadErr != nil {
419→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state for compaction: %v\n", loadErr)
420→	}
421→	if sessionState != nil {
422→		if transErr := strategy.TransitionAndLog(sessionState, session.EventCompaction, session.TransitionContext{}, session.NoOpActionHandler{}); transErr != nil {
423→			fmt.Fprintf(os.Stderr, "Warning: compaction transition failed: %v\n", transErr)
424→		}
425→
426→		// Reset transcript offset since the transcript may be truncated/reorganized
427→		sessionState.CheckpointTranscriptStart = 0
428→
429→		if saveErr := strategy.SaveSessionState(sessionState); saveErr != nil {
430→			fmt.Fprintf(os.Stderr, "Warning: failed to save session state after compaction: %v\n", saveErr)
431→		}
432→	}
433→
434→	fmt.Fprintf(os.Stderr, "Context compaction: transcript offset reset\n")
435→	return nil
436→}
