479→// handleLifecycleSubagentEnd handles subagent end: detects changes, saves task checkpoint.
480→func handleLifecycleSubagentEnd(ag agent.Agent, event *agent.Event) error {
481→	logCtx := logging.WithAgent(logging.WithComponent(context.Background(), "lifecycle"), ag.Name())
482→	logging.Info(logCtx, "subagent-end",
483→		slog.String("event", event.Type.String()),
484→		slog.String("session_id", event.SessionID),
485→		slog.String("tool_use_id", event.ToolUseID),
486→		slog.String("subagent_id", event.SubagentID),
487→	)
488→
489→	// Extract subagent type and description from tool input
490→	subagentType, taskDescription := ParseSubagentTypeAndDescription(event.ToolInput)
491→
492→	// Determine subagent transcript path
493→	transcriptDir := filepath.Dir(event.SessionRef)
494→	var subagentTranscriptPath string
495→	if event.SubagentID != "" {
496→		subagentTranscriptPath = AgentTranscriptPath(transcriptDir, event.SubagentID)
497→		if !fileExists(subagentTranscriptPath) {
498→			subagentTranscriptPath = ""
499→		}
500→	}
501→
502→	// Log context
503→	fmt.Fprintf(os.Stderr, "[entire] Subagent completed\n")
504→	fmt.Fprintf(os.Stderr, "  Session ID: %s\n", event.SessionID)
505→	fmt.Fprintf(os.Stderr, "  Tool Use ID: %s\n", event.ToolUseID)
506→	if event.SubagentID != "" {
507→		fmt.Fprintf(os.Stderr, "  Agent ID: %s\n", event.SubagentID)
508→	}
509→	if subagentTranscriptPath != "" {
510→		fmt.Fprintf(os.Stderr, "  Subagent Transcript: %s\n", subagentTranscriptPath)
511→	}
512→
513→	// Extract modified files from subagent transcript
514→	var modifiedFiles []string
515→	if analyzer, ok := ag.(agent.TranscriptAnalyzer); ok {
516→		transcriptToScan := event.SessionRef
517→		if subagentTranscriptPath != "" {
518→			transcriptToScan = subagentTranscriptPath
519→		}
520→		if files, _, fileErr := analyzer.ExtractModifiedFilesFromOffset(transcriptToScan, 0); fileErr != nil {
521→			fmt.Fprintf(os.Stderr, "Warning: failed to extract modified files from subagent: %v\n", fileErr)
522→		} else {
523→			modifiedFiles = files
524→		}
525→	}
526→
527→	// Load pre-task state and detect file changes
528→	preState, err := LoadPreTaskState(event.ToolUseID)
529→	if err != nil {
530→		fmt.Fprintf(os.Stderr, "Warning: failed to load pre-task state: %v\n", err)
531→	}
532→	changes, err := DetectFileChanges(preState.PreUntrackedFiles())
533→	if err != nil {
534→		fmt.Fprintf(os.Stderr, "Warning: failed to compute file changes: %v\n", err)
535→	}
536→
537→	// Get repo root and normalize paths
538→	repoRoot, err := paths.RepoRoot()
539→	if err != nil {
540→		return fmt.Errorf("failed to get repo root: %w", err)
541→	}
542→
543→	relModifiedFiles := FilterAndNormalizePaths(modifiedFiles, repoRoot)
544→	var relNewFiles, relDeletedFiles []string
545→	if changes != nil {
546→		relNewFiles = FilterAndNormalizePaths(changes.New, repoRoot)
547→		relDeletedFiles = FilterAndNormalizePaths(changes.Deleted, repoRoot)
548→	}
549→
550→	// If no changes, skip
551→	if len(relModifiedFiles) == 0 && len(relNewFiles) == 0 && len(relDeletedFiles) == 0 {
552→		fmt.Fprintf(os.Stderr, "[entire] No file changes detected, skipping task checkpoint\n")
553→		_ = CleanupPreTaskState(event.ToolUseID) //nolint:errcheck // best-effort cleanup
554→		return nil
555→	}
556→
557→	// Find checkpoint UUID from main transcript (best-effort)
558→	var checkpointUUID string
559→	// Use the existing CLI-level checkpoint UUID finder
560→	mainLines, _, _ := parseTranscriptForCheckpointUUID(event.SessionRef) //nolint:errcheck // best-effort
561→	if mainLines != nil {
562→		checkpointUUID, _ = FindCheckpointUUID(mainLines, event.ToolUseID)
563→	}
564→
565→	// Get git author
566→	author, err := GetGitAuthor()
567→	if err != nil {
568→		return fmt.Errorf("failed to get git author: %w", err)
569→	}
570→
571→	// Build task checkpoint context
572→	strat := GetStrategy()
573→	agentType := ag.Type()
574→
575→	ctx := strategy.TaskStepContext{
576→		SessionID:              event.SessionID,
577→		ToolUseID:              event.ToolUseID,
578→		AgentID:                event.SubagentID,
579→		ModifiedFiles:          relModifiedFiles,
580→		NewFiles:               relNewFiles,
581→		DeletedFiles:           relDeletedFiles,
582→		TranscriptPath:         event.SessionRef,
583→		SubagentTranscriptPath: subagentTranscriptPath,
584→		CheckpointUUID:         checkpointUUID,
585→		AuthorName:             author.Name,
586→		AuthorEmail:            author.Email,
587→		SubagentType:           subagentType,
588→		TaskDescription:        taskDescription,
589→		AgentType:              agentType,
590→	}
591→
592→	if err := strat.SaveTaskStep(ctx); err != nil {
593→		return fmt.Errorf("failed to save task step: %w", err)
594→	}
595→
596→	_ = CleanupPreTaskState(event.ToolUseID) //nolint:errcheck // best-effort cleanup
597→	return nil
598→}
599→
600→// --- Helper functions ---
601→
602→// resolveTranscriptOffset determines the transcript offset to use for parsing.
603→// Prefers pre-prompt state, falls back to session state.
604→func resolveTranscriptOffset(preState *PrePromptState, sessionID string) int {
605→	if preState != nil && preState.TranscriptOffset > 0 {
606→		fmt.Fprintf(os.Stderr, "Pre-prompt state found: parsing transcript from offset %d\n", preState.TranscriptOffset)
607→		return preState.TranscriptOffset
608→	}
609→
610→	// Fall back to session state (e.g., auto-commit strategy updates it after each save)
611→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
612→	if loadErr != nil {
613→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state: %v\n", loadErr)
614→		return 0
615→	}
616→	if sessionState != nil && sessionState.CheckpointTranscriptStart > 0 {
617→		fmt.Fprintf(os.Stderr, "Session state found: parsing transcript from offset %d\n", sessionState.CheckpointTranscriptStart)
618→		return sessionState.CheckpointTranscriptStart
619→	}
620→
621→	return 0
622→}
623→
624→// updateAutoCommitTranscriptPosition updates the session state with the new transcript position
625→// for the auto-commit strategy.
626→func updateAutoCommitTranscriptPosition(sessionID string, newPosition int) {
627→	sessionState, loadErr := strategy.LoadSessionState(sessionID)
628→	if loadErr != nil {
629→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state: %v\n", loadErr)
630→		return
631→	}
632→	if sessionState == nil {
633→		sessionState = &strategy.SessionState{
634→			SessionID: sessionID,
635→		}
636→	}
637→	sessionState.CheckpointTranscriptStart = newPosition
638→	sessionState.StepCount++
639→	if updateErr := strategy.SaveSessionState(sessionState); updateErr != nil {
640→		fmt.Fprintf(os.Stderr, "Warning: failed to update session state: %v\n", updateErr)
641→	} else {
642→		fmt.Fprintf(os.Stderr, "Updated session state: transcript position=%d, checkpoint=%d\n",
643→			newPosition, sessionState.StepCount)
644→	}
645→}
646→
647→// createContextFile creates a context.md file for the session checkpoint.
648→// This is a unified version that works for all agents.
649→func createContextFile(contextFile, commitMessage, sessionID string, prompts []string, summary string) error {
650→	var sb strings.Builder
651→
652→	sb.WriteString("# Session Context\n\n")
653→	sb.WriteString(fmt.Sprintf("Session ID: %s\n", sessionID))
654→	sb.WriteString(fmt.Sprintf("Commit Message: %s\n\n", commitMessage))
655→
656→	if len(prompts) > 0 {
657→		sb.WriteString("## Prompts\n\n")
658→		for i, p := range prompts {
659→			sb.WriteString(fmt.Sprintf("### Prompt %d\n\n%s\n\n", i+1, p))
660→		}
661→	}
662→
663→	if summary != "" {
664→		sb.WriteString("## Summary\n\n")
665→		sb.WriteString(summary)
666→		sb.WriteString("\n")
667→	}
668→
669→	if err := os.WriteFile(contextFile, []byte(sb.String()), 0o600); err != nil {
670→		return fmt.Errorf("failed to write context file: %w", err)
671→	}
672→	return nil
673→}
674→
675→// parseTranscriptForCheckpointUUID is a thin wrapper around transcript parsing for checkpoint UUID lookup.
676→// Returns parsed transcript lines for use with FindCheckpointUUID.
677→func parseTranscriptForCheckpointUUID(transcriptPath string) ([]transcriptLine, int, error) {
678→	lines, total, err := transcript.ParseFromFileAtLine(transcriptPath, 0)
679→	if err != nil {
680→		return nil, 0, fmt.Errorf("parsing transcript for checkpoint UUID: %w", err)
681→	}
682→	return lines, total, nil
683→}
684→
685→// transitionSessionTurnEnd transitions the session phase to IDLE and dispatches turn-end actions.
686→func transitionSessionTurnEnd(sessionID string) {
687→	turnState, loadErr := strategy.LoadSessionState(sessionID)
688→	if loadErr != nil {
689→		fmt.Fprintf(os.Stderr, "Warning: failed to load session state for turn end: %v\n", loadErr)
690→		return
691→	}
692→	if turnState == nil {
693→		return
694→	}
695→	if err := strategy.TransitionAndLog(turnState, session.EventTurnEnd, session.TransitionContext{}, session.NoOpActionHandler{}); err != nil {
696→		fmt.Fprintf(os.Stderr, "Warning: turn-end transition failed: %v\n", err)
697→	}
698→
699→	// Always dispatch to strategy for turn-end handling. The strategy reads
700→	// work items from state (e.g. TurnCheckpointIDs), not the action list.
701→	strat := GetStrategy()
702→	if handler, ok := strat.(strategy.TurnEndHandler); ok {
703→		if err := handler.HandleTurnEnd(turnState); err != nil {
704→			fmt.Fprintf(os.Stderr, "Warning: turn-end action dispatch failed: %v\n", err)
705→		}
706→	}
707→
708→	if updateErr := strategy.SaveSessionState(turnState); updateErr != nil {
709→		fmt.Fprintf(os.Stderr, "Warning: failed to update session phase on turn end: %v\n", updateErr)
710→	}
711→}
712→
713→// markSessionEnded transitions the session to ENDED phase via the state machine.
714→func markSessionEnded(sessionID string) error {
715→	state, err := strategy.LoadSessionState(sessionID)
716→	if err != nil {
717→		return fmt.Errorf("failed to load session state: %w", err)
718→	}
719→	if state == nil {
720→		return nil // No state file, nothing to update
721→	}
722→
723→	if transErr := strategy.TransitionAndLog(state, session.EventSessionStop, session.TransitionContext{}, session.NoOpActionHandler{}); transErr != nil {
724→		fmt.Fprintf(os.Stderr, "Warning: session stop transition failed: %v\n", transErr)
725→	}
726→
727→	now := time.Now()
728→	state.EndedAt = &now
729→
730→	if err := strategy.SaveSessionState(state); err != nil {
731→		return fmt.Errorf("failed to save session state: %w", err)
732→	}
733→	return nil
734→}
