736→// logFileChanges logs the files modified, created, and deleted during a session.
737→func logFileChanges(modified, newFiles, deleted []string) {
738→	fmt.Fprintf(os.Stderr, "Files modified during session (%d):\n", len(modified))
739→	for _, file := range modified {
740→		fmt.Fprintf(os.Stderr, "  - %s\n", file)
741→	}
742→	if len(newFiles) > 0 {
