744→		for _, file := range newFiles {
745→			fmt.Fprintf(os.Stderr, "  - %s\n", file)
746→		}
747→	}
748→	if len(deleted) > 0 {
749→		fmt.Fprintf(os.Stderr, "Files deleted (%d):\n", len(deleted))
750→		for _, file := range deleted {
751→			fmt.Fprintf(os.Stderr, "  - %s\n", file)
752→		}
753→	}
