457→func (c *ClaudeCodeAgent) CalculateTotalTokenUsage(sessionRef string, fromOffset int, subagentsDir string) (*agent.TokenUsage, error) {
458→	return CalculateTotalTokenUsage(sessionRef, fromOffset, subagentsDir)
