277→// Gemini uses JSON format with a messages array, so position is the message count.
278→// Returns 0 if the file doesn't exist or is empty.
279→func (g *GeminiCLIAgent) GetTranscriptPosition(path string) (int, error) {
280→	if path == "" {
281→		return 0, nil
282→	}
283→
284→	data, err := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
285→	if err != nil {
286→		if os.IsNotExist(err) {
287→			return 0, nil
288→		}
289→		return 0, fmt.Errorf("failed to read transcript: %w", err)
290→	}
291→
292→	if len(data) == 0 {
293→		return 0, nil
294→	}
295→
296→	transcript, err := ParseTranscript(data)
297→	if err != nil {
298→		return 0, fmt.Errorf("failed to parse transcript: %w", err)
299→	}
300→
301→	return len(transcript.Messages), nil
302→}
303→
304→// ExtractModifiedFilesFromOffset extracts files modified since a given message index.
305→// For Gemini (JSON format), offset is the starting message index.
306→// Returns:
307→//   - files: list of file paths modified by Gemini (from Write/Edit tools)
308→//   - currentPosition: total number of messages in the transcript
309→//   - error: any error encountered during reading
310→func (g *GeminiCLIAgent) ExtractModifiedFilesFromOffset(path string, startOffset int) (files []string, currentPosition int, err error) {
311→	if path == "" {
312→		return nil, 0, nil
313→	}
314→
315→	data, readErr := os.ReadFile(path) //nolint:gosec // Reading from controlled transcript path
316→	if readErr != nil {
317→		if os.IsNotExist(readErr) {
318→			return nil, 0, nil
319→		}
320→		return nil, 0, fmt.Errorf("failed to read transcript: %w", readErr)
321→	}
322→
323→	if len(data) == 0 {
324→		return nil, 0, nil
325→	}
326→
327→	transcript, parseErr := ParseTranscript(data)
328→	if parseErr != nil {
329→		return nil, 0, parseErr
330→	}
331→
332→	totalMessages := len(transcript.Messages)
333→
334→	// Extract files from messages starting at startOffset
335→	fileSet := make(map[string]bool)
336→	for i := startOffset; i < len(transcript.Messages); i++ {
337→		msg := transcript.Messages[i]
338→		// Only process gemini messages (assistant messages)
339→		if msg.Type != MessageTypeGemini {
340→			continue
341→		}
342→
343→		// Process tool calls in this message
344→		for _, toolCall := range msg.ToolCalls {
345→			// Check if it's a file modification tool
346→			isModifyTool := false
347→			for _, name := range FileModificationTools {
348→				if toolCall.Name == name {
349→					isModifyTool = true
350→					break
351→				}
352→			}
353→
354→			if !isModifyTool {
355→				continue
356→			}
357→
358→			// Extract file path from args map
359→			var file string
360→			if fp, ok := toolCall.Args["file_path"].(string); ok && fp != "" {
361→				file = fp
362→			} else if p, ok := toolCall.Args["path"].(string); ok && p != "" {
363→				file = p
364→			} else if fn, ok := toolCall.Args["filename"].(string); ok && fn != "" {
365→				file = fn
366→			}
367→
368→			if file != "" && !fileSet[file] {
369→				fileSet[file] = true
370→				files = append(files, file)
371→			}
372→		}
373→	}
374→
375→	return files, totalMessages, nil
376→}
377→
378→// ChunkTranscript splits a Gemini JSON transcript by distributing messages across chunks.
379→// Gemini uses JSON format with a {"messages": [...]} structure, so chunking splits
380→// the messages array while preserving the JSON structure in each chunk.
381→func (g *GeminiCLIAgent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
382→	var transcript GeminiTranscript
383→	if err := json.Unmarshal(content, &transcript); err != nil {
384→		// Fall back to JSONL chunking if not valid Gemini JSON
385→		chunks, chunkErr := agent.ChunkJSONL(content, maxSize)
386→		if chunkErr != nil {
387→			return nil, fmt.Errorf("failed to chunk as JSONL: %w", chunkErr)
388→		}
389→		return chunks, nil
390→	}
391→
392→	if len(transcript.Messages) == 0 {
393→		return [][]byte{content}, nil
394→	}
395→
396→	var chunks [][]byte
397→	var currentMessages []GeminiMessage
398→	currentSize := len(`{"messages":[]}`) // Base JSON structure size
399→
400→	for i, msg := range transcript.Messages {
401→		// Marshal message to get its size
402→		msgBytes, err := json.Marshal(msg)
403→		if err != nil {
404→			logging.Warn(context.Background(), "failed to marshal Gemini message during chunking",
405→				slog.Int("message_index", i),
406→				slog.String("error", err.Error()),
407→			)
408→			continue
409→		}
410→		msgSize := len(msgBytes) + 1 // +1 for comma separator
411→
412→		if currentSize+msgSize > maxSize && len(currentMessages) > 0 {
413→			// Save current chunk
414→			chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
415→			if err != nil {
416→				return nil, fmt.Errorf("failed to marshal chunk: %w", err)
417→			}
418→			chunks = append(chunks, chunkData)
419→
420→			// Start new chunk
421→			currentMessages = nil
422→			currentSize = len(`{"messages":[]}`)
423→		}
424→
425→		currentMessages = append(currentMessages, msg)
426→		currentSize += msgSize
427→	}
428→
429→	// Add the last chunk
430→	if len(currentMessages) > 0 {
431→		chunkData, err := json.Marshal(GeminiTranscript{Messages: currentMessages})
432→		if err != nil {
433→			return nil, fmt.Errorf("failed to marshal final chunk: %w", err)
434→		}
435→		chunks = append(chunks, chunkData)
436→	}
437→
438→	// Ensure we created at least one chunk (could be empty if all messages failed to marshal)
439→	if len(chunks) == 0 {
440→		return nil, errors.New("failed to create any chunks: all messages failed to marshal")
441→	}
442→
443→	return chunks, nil
444→}
445→
446→// ReassembleTranscript merges Gemini JSON chunks by combining their message arrays.
447→func (g *GeminiCLIAgent) ReassembleTranscript(chunks [][]byte) ([]byte, error) {
448→	var allMessages []GeminiMessage
449→
450→	for _, chunk := range chunks {
451→		var transcript GeminiTranscript
452→		if err := json.Unmarshal(chunk, &transcript); err != nil {
453→			return nil, fmt.Errorf("failed to unmarshal chunk: %w", err)
454→		}
455→		allMessages = append(allMessages, transcript.Messages...)
456→	}
457→
458→	result, err := json.Marshal(GeminiTranscript{Messages: allMessages})
459→	if err != nil {
460→		return nil, fmt.Errorf("failed to marshal reassembled transcript: %w", err)
461→	}
462→	return result, nil
463→}
